for idea in ideas:
    id = idea["id"]
    folder_path = os.path.join(base_path, id)
    os.makedirs(folder_path, exist_ok=True)
    
    with open(os.path.join(folder_path, "описание.json"), "w", encoding="utf-8") as f:
        json.dump(idea, f, ensure_ascii=False, indent=2)
    print(f"Generated content for: {id}")

